const response = $input.first().json;
const data = response.data;

if (!data || (Array.isArray(data) && data.length === 0)) {
  return [{ json: { _hasPayload: false, _skipToReport: true } }];
}

const row = Array.isArray(data) ? data[0] : data;
let payload = {};
if (row.prepared_payload) {
  try { payload = JSON.parse(row.prepared_payload); } catch(e) {}
}

return [{ json: { ...row, ...payload, _hasPayload: true, _skipToReport: false } }];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Check GBP status first
let gbpReady = false;
try {
  const gbpResult = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/posting?date=' + $now.toFormat('yyyy-MM-dd') + '&platform=gbp',
    headers: headers,
    json: true
  });
  const gbpData = gbpResult.data;
  const gbpStatus = gbpData ? (Array.isArray(gbpData) && gbpData.length > 0 ? gbpData[0].status : gbpData.status) : '';
  gbpReady = (gbpStatus === 'success' || gbpStatus === 'manual_backup_sent');
} catch(e) {}

if (!gbpReady) {
  return [{ json: { ...item, _threadsStatus: 'skipped', _threadsMessage: 'GBP not ready' } }];
}

// Check Threads permissions
try {
  const permCheck = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://graph.threads.net/v1.0/' + $env.THREADS_USER_ID + '?fields=threads_publishing_limit&access_token=' + $env.THREADS_ACCESS_TOKEN,
    json: true
  });
  // If permission denied or limit reached
  if (permCheck.error) {
    throw new Error(permCheck.error.message || 'Permission denied');
  }
} catch (permError) {
  // Fallback to manual
  await this.helpers.httpRequest({
    method: 'POST',
    url: CRM + '/api/posting',
    body: {
      content_calendar_id: item.id, platform: 'threads', status: 'failed',
      error: 'Permission check failed: ' + permError.message,
      date: $now.toFormat('yyyy-MM-dd'), brand: item.brand,
      content_type: item.content_type, content_item: item.topic || '', area: item.area_id
    },
    headers: headers, json: true
  });

  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
    body: {
      chat_id: $env.TELEGRAM_CHAT_ID,
      text: '📱 Threads manual post required:\n\n' + item.threads_caption + '\n\nImage: ' + (item.direct_image_url || item.image_url || '')
    },
    json: true
  });

  return [{ json: { ...item, _threadsStatus: 'failed', _threadsMessage: 'Manual fallback sent' } }];
}

// Create Threads container
try {
  const containerResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.threads.net/v1.0/' + $env.THREADS_USER_ID + '/threads',
    body: {
      media_type: 'IMAGE',
      image_url: item.meta_image_url || item.direct_image_url,
      text: item.threads_caption,
      access_token: $env.THREADS_ACCESS_TOKEN
    },
    json: true
  });

  if (!containerResp.id) throw new Error('No container ID returned');

  // Wait 30 seconds (Threads requirement)
  await new Promise(resolve => setTimeout(resolve, 30000));

  // Publish
  const publishResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.threads.net/v1.0/' + $env.THREADS_USER_ID + '/threads_publish',
    body: {
      creation_id: containerResp.id,
      access_token: $env.THREADS_ACCESS_TOKEN
    },
    json: true
  });

  // Log success
  await this.helpers.httpRequest({
    method: 'POST',
    url: CRM + '/api/posting',
    body: {
      content_calendar_id: item.id, platform: 'threads', status: 'success',
      post_url: publishResp.id || '', date: $now.toFormat('yyyy-MM-dd'),
      brand: item.brand, content_type: item.content_type,
      content_item: item.topic || '', area: item.area_id
    },
    headers: headers, json: true
  });

  return [{ json: { ...item, _threadsStatus: 'success', _threadsMessage: 'Published' } }];

} catch (pubError) {
  // Publish failed — manual fallback
  await this.helpers.httpRequest({
    method: 'POST',
    url: CRM + '/api/posting',
    body: {
      content_calendar_id: item.id, platform: 'threads', status: 'failed',
      error: pubError.message, date: $now.toFormat('yyyy-MM-dd'),
      brand: item.brand, content_type: item.content_type,
      content_item: item.topic || '', area: item.area_id
    },
    headers: headers, json: true
  });

  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
    body: {
      chat_id: $env.TELEGRAM_CHAT_ID,
      text: '📱 Threads manual post required:\n\n' + item.threads_caption + '\n\nImage: ' + (item.direct_image_url || item.image_url || '')
    },
    json: true
  });

  return [{ json: { ...item, _threadsStatus: 'failed', _threadsMessage: 'Manual fallback sent' } }];
}

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

if (!item.id) {
  return [{ json: { _statusUpdated: false, message: 'No content ID to update' } }];
}

// Fetch all postings for this content item
try {
  const postingsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/posting?content_calendar_id=' + item.id,
    headers: headers,
    json: true
  });

  const postings = postingsResp.data || [];
  const postingList = Array.isArray(postings) ? postings : [postings];

  // Check status of each platform
  const getStatus = (platform) => {
    const p = postingList.find(x => x.platform === platform);
    return p ? p.status : 'pending';
  };

  const gbp = getStatus('gbp');
  const ig = getStatus('instagram');
  const li = getStatus('linkedin');
  const pin = getStatus('pinterest');
  const tw = getStatus('twitter');
  const threads = getStatus('threads');

  // Determine overall status
  const autoComplete = ['success', 'manual_backup_sent', 'failed'];
  const manualComplete = ['manual_posted', 'notification_sent'];

  const allDone = autoComplete.includes(gbp) && autoComplete.includes(ig) &&
    (manualComplete.includes(li) || li === 'manual_posted') &&
    autoComplete.includes(pin) &&
    (manualComplete.includes(tw) || tw === 'manual_posted') &&
    (autoComplete.includes(threads) || threads === 'failed');

  const manualPending = (li === 'notification_sent') || (tw === 'notification_sent');

  let newStatus;
  if (li === 'manual_posted' && tw === 'manual_posted') {
    newStatus = 'completed';
  } else if (manualPending) {
    newStatus = 'auto_complete_pending_manual';
  } else {
    newStatus = 'auto_complete_pending_manual';
  }

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: CRM + '/api/content/' + item.id + '/status',
    body: { status: newStatus },
    headers: headers,
    json: true
  });

  return [{ json: { ...item, _calendarStatus: newStatus, _statusUpdated: true } }];
} catch (e) {
  return [{ json: { ...item, _calendarStatus: 'unknown', _statusUpdated: false, _statusError: e.message } }];
}

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Fetch all postings for today to build the report
let postingList = [];
try {
  const postingsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/posting?date=' + $now.toFormat('yyyy-MM-dd'),
    headers: headers,
    json: true
  });
  const postings = postingsResp.data || [];
  postingList = Array.isArray(postings) ? postings : [postings];
} catch(e) {
  postingList = [];
}

// Build status map
const getStatus = (platform) => {
  const p = postingList.find(x => x.platform === platform);
  return p ? p.status : 'not_run';
};

const statusEmoji = (status) => {
  if (status === 'success') return '✅';
  if (status === 'notification_sent') return '📌';
  if (status === 'manual_posted') return '✅';
  if (status === 'manual_backup_sent') return '⚠️';
  if (status === 'failed') return '❌';
  if (status === 'blocked') return '🚫';
  if (status === 'skipped') return '⏭️';
  return '⏳';
};

const gbp = getStatus('gbp');
const ig = getStatus('instagram');
const li = getStatus('linkedin');
const pin = getStatus('pinterest');
const tw = getStatus('twitter');
const threads = getStatus('threads');

const autoStatuses = [gbp, ig, pin, threads];
const autoSuccess = autoStatuses.filter(s => s === 'success').length;
const manualStatuses = [li, tw];
const manualPending = manualStatuses.filter(s => s === 'notification_sent').length;

const brand = item.brand || 'Unknown';
const contentItem = item.topic || item.content_item || '';
const area = item.area_id || '';

const reportText = '📊 Daily Report — ' + $now.toFormat('yyyy-MM-dd') + '\n' +
  'Brand: ' + brand + ' | ' + contentItem + ' | Area: ' + area + '\n\n' +
  statusEmoji(gbp) + ' GBP: ' + gbp + '\n' +
  statusEmoji(ig) + ' Instagram: ' + ig + '\n' +
  statusEmoji(li) + ' LinkedIn: ' + li + '\n' +
  statusEmoji(pin) + ' Pinterest: ' + pin + '\n' +
  statusEmoji(tw) + ' Twitter/X: ' + tw + '\n' +
  statusEmoji(threads) + ' Threads: ' + threads + '\n\n' +
  'Total auto: ' + autoSuccess + '/4 | Manual pending: ' + manualPending + '/2';

// Send Telegram report
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: reportText },
  json: true
});

return [{ json: { report_sent: true, report: reportText } }];
